package builders

import (
	"chain/runtime"
	"strings"
	"time"
)

func assertNonEmpty(v string, field string) {
	if strings.TrimSpace(v) == "" {
		panic("missing required field: " + field)
	}
}

func assertValidRequestType(v string) {
	switch v {
	case "initial", "followup":
		return
	default:
		panic("invalid requestType: must be 'initial' or 'followup'")
	}
}

func Submit(
	_ realm,
	twitterHandle string,
	discordHandle string,
	githubURL string,
	requestType string,
	applicationDetails string,
) {
	runtime.AssertOriginCall()

	assertNonEmpty(twitterHandle, "twitterHandle")
	assertNonEmpty(discordHandle, "discordHandle")
	assertNonEmpty(githubURL, "githubURL")
	assertNonEmpty(applicationDetails, "applicationDetails")
	assertValidRequestType(requestType)

	caller := applicantAddr()
	now := time.Now()

	sub := GetSubmission(caller)
	if sub != nil {
		sub.Twitter = twitterHandle
		sub.Discord = discordHandle
		sub.GitHub = githubURL
		sub.RequestType = requestType
		sub.Details = applicationDetails
		sub.Status = StatusPending
		sub.ReviewNote = ""
		sub.SubmittedAt = now
		sub.ReviewedAt = time.Time{}
		sub.PaidAt = time.Time{}
		setSubmission(sub)
		return
	}

	setSubmission(&Submission{
		Applicant:   caller,
		Twitter:     twitterHandle,
		Discord:     discordHandle,
		GitHub:      githubURL,
		RequestType: requestType,
		Details:     applicationDetails,
		Status:      StatusPending,
		SubmittedAt: now,
	})
}

func Approve(_ realm, addr address, note string) {
	requireAdmin()

	sub := GetSubmission(addr)
	if sub == nil {
		panic("submission not found")
	}

	sub.Status = StatusApproved
	sub.ReviewNote = note
	sub.ReviewedAt = time.Now()
	setSubmission(sub)
}

func Reject(_ realm, addr address, note string) {
	requireAdmin()

	sub := GetSubmission(addr)
	if sub == nil {
		panic("submission not found")
	}

	sub.Status = StatusRejected
	sub.ReviewNote = note
	sub.ReviewedAt = time.Now()
	setSubmission(sub)
}

func MarkPaid(_ realm, addr address, note string) {
	requireAdmin()

	sub := GetSubmission(addr)
	if sub == nil {
		panic("submission not found")
	}
	if sub.Status != StatusApproved {
		panic("submission must be approved before marking paid")
	}

	sub.Status = StatusPaid
	sub.ReviewNote = note
	sub.ReviewedAt = time.Now()
	sub.PaidAt = time.Now()
	setSubmission(sub)
}

func TransferAdmin(_ realm, newAdmin address) {
	requireAdmin()

	if newAdmin == "" {
		panic("new admin cannot be empty")
	}

	admin = newAdmin
}

package builders

import (
	"gno.land/p/jeronimoalbi/mdform"
	"gno.land/p/moul/md"
	"gno.land/p/moul/txlink"
)

func renderSubmission(sub *Submission) string {
	out := "### " + string(sub.Applicant) + "\n\n"
	out += "- **Status:** " + sub.Status.String() + "\n"
	out += "- **Twitter:** " + sub.Twitter + "\n"
	out += "- **Discord:** " + sub.Discord + "\n"
	out += "- **GitHub:** " + sub.GitHub + "\n"
	out += "- **Request Type:** " + sub.RequestType + "\n"
	out += "- **Details:** " + sub.Details + "\n"
	out += "- **Submitted:** " + sub.SubmittedAt.Format("2006-01-02 15:04:05") + "\n"

	if !sub.ReviewedAt.IsZero() {
		out += "- **Reviewed:** " + sub.ReviewedAt.Format("2006-01-02 15:04:05") + "\n"
	}
	if !sub.PaidAt.IsZero() {
		out += "- **Paid:** " + sub.PaidAt.Format("2006-01-02 15:04:05") + "\n"
	}
	if sub.ReviewNote != "" {
		out += "- **Note:** " + sub.ReviewNote + "\n"
	}

	out += "\n"
	return out
}

func renderAdminActions(sub *Submission) string {
	approveLink := txlink.NewLink("Approve").
		AddArgs(
			"addr", string(sub.Applicant),
			"note", "approved",
		).
		URL()

	rejectLink := txlink.NewLink("Reject").
		AddArgs(
			"addr", string(sub.Applicant),
			"note", "rejected",
		).
		URL()

	out := md.Link("✅ Approve", approveLink) + " | " + md.Link("❌ Reject", rejectLink)

	if sub.Status == StatusApproved {
		paidLink := txlink.NewLink("MarkPaid").
			AddArgs(
				"addr", string(sub.Applicant),
				"note", "paid",
			).
			URL()

		out += " | " + md.Link("💸 Mark Paid", paidLink)
	}

	return out + "\n"
}

func renderApplyForm() string {
	form := mdform.New(
		"exec", "Submit",
		"path", "/r/examples/builders",
	)

	form.Input(
		"twitterHandle",
		"placeholder", "@yourhandle",
		"required", "true",
		"description", "Twitter / X handle",
	)

	form.Input(
		"discordHandle",
		"placeholder", "username or username#1234",
		"required", "true",
		"description", "Discord handle",
	)

	form.Input(
		"githubURL",
		"placeholder", "https://github.com/yourname",
		"required", "true",
		"description", "GitHub profile or repository URL",
	)

	form.Select(
		"requestType",
		"initial",
		"selected", "true",
		"required", "true",
		"description", "Request type",
	)
	form.Select(
		"requestType",
		"followup",
	)

	form.Textarea(
		"applicationDetails",
		"placeholder", "What are you building, what do you need funds for, and if this is a follow-up request, what activity should reviewers look at?",
		"required", "true",
		"rows", "8",
	)

	return form.String()
}

func Render(path string) string {
	if path == "apply" {
		out := "# Apply for Builder Faucet\n\n"
		out += "Submit your faucet application below.\n\n"
		out += renderApplyForm()
		out += "\n"
		out += md.Link("← Back to Registry", "/r/examples/builders") + "\n"
		return out
	}

	if path == "admin" {
		out := "# Admin Panel\n\n"
		out += "**Admin:** `" + string(Admin()) + "`\n\n"
		out += md.Link("← Back to Registry", "/r/examples/builders") + "\n\n"

		if TotalSubmissions() == 0 {
			out += "No submissions yet.\n"
			return out
		}

		out += "## Review Queue\n\n"
		for i := 0; i < TotalSubmissions(); i++ {
			sub := SubmissionAt(i)
			out += renderSubmission(sub)
			out += renderAdminActions(sub)
			out += "\n---\n\n"
		}
		return out
	}

	out := "# Builder Faucet Registry\n\n"
	out += "**Total submissions:** " + itoa(TotalSubmissions()) + "\n\n"
	out += "**Approved:** " + itoa(TotalApproved()) + "\n\n"
	out += "**Paid:** " + itoa(TotalPaid()) + "\n\n"

	out += md.Link("📝 Apply for Faucet", "/r/examples/builders:apply")
	out += " | "
	out += md.Link("🔐 Admin Panel", "/r/examples/builders:admin")
	out += "\n\n---\n\n"

	if TotalSubmissions() == 0 {
		out += "No submissions yet.\n"
		return out
	}

	out += "## Submissions\n\n"
	for i := 0; i < TotalSubmissions(); i++ {
		sub := SubmissionAt(i)
		out += renderSubmission(sub)
		out += "---\n\n"
	}

	return out
}

func itoa(n int) string {
	if n == 0 {
		return "0"
	}

	neg := false
	if n < 0 {
		neg = true
		n = -n
	}

	s := ""
	for n > 0 {
		s = string(rune('0'+(n%10))) + s
		n /= 10
	}

	if neg {
		return "-" + s
	}
	return s
}

package builders

import "chain/runtime"

var (
	admin       address
	submissions []*Submission
	webPath     string = "r/examples/builders"
)

func init() {
	admin = "g1778y2yphxs2wpuaflsy5y9qwcd4gttn4g5yjx5"
}

func Admin() address {
	return admin
}

func applicantAddr() address {
	return runtime.OriginCaller()
}

func requireAdmin() {
	if runtime.OriginCaller() != admin {
		panic("admin only")
	}
}

func GetSubmission(addr address) *Submission {
	for _, sub := range submissions {
		if sub.Applicant == addr {
			return sub
		}
	}
	return nil
}

func MySubmission() *Submission {
	return GetSubmission(applicantAddr())
}

func setSubmission(sub *Submission) {
	for i, existing := range submissions {
		if existing.Applicant == sub.Applicant {
			submissions[i] = sub
			return
		}
	}
	submissions = append(submissions, sub)
}

func TotalSubmissions() int {
	return len(submissions)
}

func SubmissionAt(i int) *Submission {
	if i < 0 || i >= len(submissions) {
		panic("index out of range")
	}
	return submissions[i]
}

func TotalApproved() int {
	count := 0
	for _, sub := range submissions {
		if sub.Status == StatusApproved || sub.Status == StatusPaid {
			count++
		}
	}
	return count
}

func TotalPaid() int {
	count := 0
	for _, sub := range submissions {
		if sub.Status == StatusPaid {
			count++
		}
	}
	return count
}

